public sealed interface Result<T> permits Result.Success, Result.Failure {
    record Success<T>(T value) implements Result<T> {}
    record Failure<T>(String error) implements Result<T> {}

    static <T> Result<T> of(java.util.concurrent.Callable<T> supplier) {
        try { return new Success<>(supplier.call()); }
        catch (Exception e) { return new Failure<>(e.getMessage()); }
    }

    default <R> Result<R> map(java.util.function.Function<T, R> fn) {
        return switch (this) {
            case Success<T> s -> Result.of(() -> fn.apply(s.value()));
            case Failure<T> f -> new Failure<>(f.error());
        };
    }

    default T orElse(T defaultValue) {
        return switch (this) {
            case Success<T> s -> s.value();
            case Failure<T> f -> defaultValue;
        };
    }
}

import java.util.concurrent.StructuredTaskScope;

public class UserProfileService {
    record UserProfile(String name, String email, int orderCount) {}

    UserProfile fetchProfile(long userId) throws Exception {
        try (var scope = new StructuredTaskScope.ShutdownOnFailure()) {
            var nameTask = scope.fork(() -> fetchName(userId));
            var emailTask = scope.fork(() -> fetchEmail(userId));
            var ordersTask = scope.fork(() -> fetchOrderCount(userId));

            scope.join();           // Wait for all
            scope.throwIfFailed();  // Propagate errors

            return new UserProfile(
                nameTask.get(), emailTask.get(), ordersTask.get()
            );
        }
        // If any subtask fails, others are automatically cancelled
    }

    private String fetchName(long id) { return "John"; }
    private String fetchEmail(long id) { return "john@example.com"; }
    private int fetchOrderCount(long id) { return 42; }
}

import java.util.*;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.function.Consumer;

public class EventBus {
    private final Map<Class<?>, List<Consumer<?>>> subscribers = new HashMap<>();

    public <T> void subscribe(Class<T> eventType, Consumer<T> handler) {
        subscribers.computeIfAbsent(eventType, k -> new CopyOnWriteArrayList<>()).add(handler);
    }

    @SuppressWarnings("unchecked")
    public <T> void publish(T event) {
        List<Consumer<?>> handlers = subscribers.get(event.getClass());
        if (handlers != null) {
            for (Consumer<?> handler : handlers) {
                ((Consumer<T>) handler).accept(event);
            }
        }
    }

    public <T> void unsubscribe(Class<T> eventType, Consumer<T> handler) {
        List<Consumer<?>> handlers = subscribers.get(eventType);
        if (handlers != null) handlers.remove(handler);
    }
}

