public sealed interface PList<T> permits PList.Nil, PList.Cons {
    record Nil<T>() implements PList<T> {}
    record Cons<T>(T head, PList<T> tail) implements PList<T> {}

    static <T> PList<T> empty() { return new Nil<>(); }

    default PList<T> prepend(T value) { return new Cons<>(value, this); }

    default int size() {
        return switch (this) {
            case Nil<?> n -> 0;
            case Cons<T> c -> 1 + c.tail().size();
        };
    }

    default boolean contains(T value) {
        return switch (this) {
            case Nil<?> n -> false;
            case Cons<T> c -> c.head().equals(value) || c.tail().contains(value);
        };
    }

    default PList<T> reverse() {
        PList<T> result = empty();
        PList<T> current = this;
        while (current instanceof Cons<T> c) {
            result = result.prepend(c.head());
            current = c.tail();
        }
        return result;
    }
}
